CustomField.formula:
MIN(
  /* Initial Term Discount */
  IF(
    Initial_Term_Discount__c > 30, 90,
    IF(
      Initial_Term_Discount__c = 30, 100,
      IF(
        Initial_Term_Discount__c < 1, 110,
        100
      )
    )
  ),

  /* Min YoY Committed Spend */
  IF(
    Min_year_on_year_committed_spend__c < 5, 90,
    IF(
      Min_year_on_year_committed_spend__c >= 5 && Min_year_on_year_committed_spend__c <= 6.99, 100,
      IF(
        Min_year_on_year_committed_spend__c > 7, 110,
        100
      )
    )
  ),

  /* Future Pricing Commitment */
  IF(Future_Pricing_Commitment__c, 100, 90),

  /* Product Development Obligation */
  IF(Product_Development_Obligation__c, 100, 90),

  /* Termination Clause */
  IF(Includes_Termination_Clause__c, 100, 90),

  /* Billing Frequency */
  IF(
    TEXT(SBQQ__BillingFrequency__c) = "Annual", 100, 90
  ),

  /* Payment Terms */
  IF(
    OR(TEXT(Software_Payment_Terms__c) = "Net 30", TEXT(Software_Payment_Terms__c) = "Net 60"),
    100,
    90
  )
)
